interface User {
  id: number;
  name: string;
  profile: { bio: string; avatar: string };
}

type PartialUser = Partial<User>;

function updateUser(user: PartialUser): User {
  return {
    id: user.id ?? 0,
    name: user.name ?? 'Unknown',
    profile: user.profile ?? { bio: '', avatar: '' }
  };
}

let updatedUser = updateUser({ name: 'Alice', profile: { bio: 'Developer' } });

console.log(updatedUser); // { id: 0, name: 'Alice', profile: { bio: 'Developer', avatar: '' } }

